function aabbOverlap(a, b) {  // boxes: {x, y, w, h}
  return a.x < b.x + b.w && a.x + a.w > b.x &&
         a.y < b.y + b.h && a.y + a.h > b.y;
}
// Push `m` (moving, has vx/vy) out of solid `s` along the shallower axis.
function resolveAABB(m, s) {
  if (!aabbOverlap(m, s)) return null;
  const dx1 = (s.x + s.w) - m.x;      // push right
  const dx2 = (m.x + m.w) - s.x;      // push left
  const dy1 = (s.y + s.h) - m.y;      // push down
  const dy2 = (m.y + m.h) - s.y;      // push up
  const px = dx1 < dx2 ? dx1 : -dx2;
  const py = dy1 < dy2 ? dy1 : -dy2;
  if (Math.abs(px) < Math.abs(py)) { m.x += px; m.vx = 0; return px > 0 ? "left" : "right"; }
  m.y += py; m.vy = 0;
  return py > 0 ? "top" : "bottom";   // "bottom" => landed on s (grounded)
}

// anims: name -> {frames: [{sx,sy,sw,sh}...], fps, loop}
function makeAnimator(image, anims) {
  const a = { image, anims, name: null, t: 0, idx: 0, done: false };
  a.play = (name, restart = false) => {
    if (a.name === name && !restart) return;
    a.name = name; a.t = 0; a.idx = 0; a.done = false;
  };
  a.update = (dt) => {
    const cur = a.anims[a.name]; if (!cur || a.done) return;
    a.t += dt;
    const n = Math.floor(a.t * cur.fps);
    if (cur.loop) a.idx = n % cur.frames.length;
    else { a.idx = Math.min(n, cur.frames.length - 1); a.done = n >= cur.frames.length; }
  };
  a.draw = (ctx, x, y, w, h, flipX = false) => {
    const cur = a.anims[a.name]; if (!cur) return;
    const f = cur.frames[a.idx];
    ctx.save();
    if (flipX) { ctx.translate(x + w, y); ctx.scale(-1, 1); }
    else ctx.translate(x, y);
    ctx.drawImage(a.image, f.sx, f.sy, f.sw, f.sh, 0, 0, w, h);
    ctx.restore();
  };
  return a;
}

